func recurringFormTitle(inv *domain.RecurringInvoice) string {
	if inv == nil {
		return "New Recurring Invoice"
	}
	return "Edit Recurring Invoice"
}

func recurringFormSubtitle(inv *domain.RecurringInvoice) string {
	if inv == nil {
		return "Set up a new recurring billing schedule"
	}
	return "Update recurring invoice details"
}

func recurringFormSignals(inv *domain.RecurringInvoice) string {
	if inv == nil {
		return `{customerID:'',customerName:'',frequency:'monthly',dayOfMonth:'1',lineProductIDs:['','',''],lineProductNames:['','',''],lineDescriptions:['','',''],lineQuantities:['1','1','1'],lineUnitPrices:['','','']}`
	}
	// Pre-fill with existing data
	productNames := "['','','']"
	descriptions := "['','','']"
	quantities := "['1','1','1']"
	unitPrices := "['','','']"
	productIDs := "['','','']"

	if len(inv.Lines) > 0 {
		pn := "["
		desc := "["
		qty := "["
		up := "["
		pid := "["
		for i := 0; i < 3; i++ {
			if i > 0 {
				pn += ","
				desc += ","
				qty += ","
				up += ","
				pid += ","
			}
			if i < len(inv.Lines) {
				pn += fmt.Sprintf("'%s'", inv.Lines[i].ProductName)
				desc += fmt.Sprintf("'%s'", inv.Lines[i].Description)
				qty += fmt.Sprintf("'%d'", inv.Lines[i].Quantity)
				up += fmt.Sprintf("'%s'", inv.Lines[i].UnitPrice.DisplayAmount())
				pid += fmt.Sprintf("'%s'", inv.Lines[i].ProductID)
			} else {
				pn += "''"
				desc += "''"
				qty += "'1'"
				up += "''"
				pid += "''"
			}
		}
		productNames = pn + "]"
		descriptions = desc + "]"
		quantities = qty + "]"
		unitPrices = up + "]"
		productIDs = pid + "]"
	}

	return fmt.Sprintf(
		`{customerID:'%s',customerName:'%s',frequency:'%s',dayOfMonth:'%d',lineProductIDs:%s,lineProductNames:%s,lineDescriptions:%s,lineQuantities:%s,lineUnitPrices:%s}`,
		inv.CustomerID, inv.CustomerName, string(inv.Schedule.Frequency), inv.Schedule.DayOfMonth,
		productIDs, productNames, descriptions, quantities, unitPrices,
	)
}

func recurringFormAction(inv *domain.RecurringInvoice) string {
	if inv == nil {
		return "@post('/api/recurring')"
	}
	return fmt.Sprintf("@put('/api/recurring/%s')", inv.ID)
}

func recurringFormButtonText(inv *domain.RecurringInvoice) string {
	if inv == nil {
		return "Create Recurring Invoice"
	}
	return "Save Changes"
}

func formatLastRunDate(t *time.Time) string {
	if t == nil {
		return "Never"
	}
	return t.Format("2006-01-02")
}

